DECLARE @Action VARCHAR(10) = '@{pipeline().parameters.Action}';
DECLARE @PipelineName VARCHAR(255) = '@{pipeline().parameters.PipelineName}';
DECLARE @TableName VARCHAR(255) = '@{pipeline().parameters.TableName}';
DECLARE @LayerName VARCHAR(50) = '@{pipeline().parameters.LayerName}';
DECLARE @ErrorMessage VARCHAR(MAX) = '@{pipeline().parameters.ErrorMessage}';

-- ---------------------------------------------------------
-- 🚀 CASE 1 : ACTION = START
-- ---------------------------------------------------------
IF @Action = 'START'
BEGIN
    DECLARE @new_run_id UNIQUEIDENTIFIER = NEWID();

    INSERT INTO wh_gold.dbo.pipeline_run_log (
        log_id, run_id, pipeline_name, pipeline_step, layer_name, 
        status, start_time, end_time, duration_seconds, rows_inserted, error_message, run_date
    )
    VALUES (
        NEWID(), @new_run_id, @PipelineName, @TableName, @LayerName,
        'STARTED', SYSDATETIME(), NULL, NULL, NULL, NULL, CAST(SYSDATETIME() AS DATE)
    );
END

-- ---------------------------------------------------------
-- ✅ CASE 2 : ACTION = SUCCESS
-- ---------------------------------------------------------
ELSE IF @Action = 'SUCCESS'
BEGIN
    DECLARE @start_time_success DATETIME2(6);
    DECLARE @run_id_success UNIQUEIDENTIFIER;
    DECLARE @rows_count INT = NULL; -- Par défaut à NULL si la table n'existe pas ou est un nom logique
    DECLARE @sql NVARCHAR(MAX);

    -- 1. Récupération du run_id et du start_time de l'étape STARTED
    SELECT TOP 1 @start_time_success = start_time, @run_id_success = run_id
    FROM wh_gold.dbo.pipeline_run_log    
    WHERE pipeline_name = @PipelineName AND pipeline_step = @TableName AND status = 'STARTED'
    ORDER BY start_time DESC;

    -- 2. Compter dynamiquement les lignes de la table cible avec sécurité TRY/CATCH
    BEGIN TRY
        -- Si @TableName contient déjà des points (ex: lh_bronze.dbo.firebase_ingestion), 
        -- on l'intègre directement sans rajouter de "dbo." devant.
        SET @sql = N'SELECT @cnt = COUNT(*) FROM ' + @TableName;
        EXEC sp_executesql @sql, N'@cnt INT OUTPUT', @cnt = @rows_count OUTPUT;
    END TRY
    BEGIN CATCH
        -- Si @TableName est un nom descriptif (ex: 'Ingestion_Firebase') ou si la table n'existe pas,
        -- SQL va générer une erreur. Le CATCH l'intercepte proprement pour éviter de faire planter votre pipeline.
        SET @rows_count = NULL; 
    END CATCH

    -- 3. Insertion du log de succès
    INSERT INTO wh_gold.dbo.pipeline_run_log (
        log_id, run_id, pipeline_name, pipeline_step, layer_name, 
        status, start_time, end_time, duration_seconds, rows_inserted, error_message, run_date
    )
    VALUES (
        NEWID(), @run_id_success, @PipelineName, @TableName, @LayerName,
        'SUCCESS', @start_time_success, SYSDATETIME(), DATEDIFF(SECOND, @start_time_success, SYSDATETIME()), @rows_count, NULL, CAST(SYSDATETIME() AS DATE)
    );
END

-- ---------------------------------------------------------
-- ❌ CASE 3 : ACTION = FAILED
-- ---------------------------------------------------------
ELSE IF @Action = 'FAILED'
BEGIN
    DECLARE @start_time_fail DATETIME2(6);
    DECLARE @run_id_fail UNIQUEIDENTIFIER;

    -- 1. Récupération du run_id et du start_time
    SELECT TOP 1 @start_time_fail = start_time, @run_id_fail = run_id
    FROM wh_gold.dbo.pipeline_run_log
    WHERE pipeline_name = @PipelineName AND pipeline_step = @TableName AND status = 'STARTED'
    ORDER BY start_time DESC;

    -- 2. Insertion du log d'échec
    INSERT INTO wh_gold.dbo.pipeline_run_log (
        log_id, run_id, pipeline_name, pipeline_step, layer_name, 
        status, start_time, end_time, duration_seconds, rows_inserted, error_message, run_date
    )
    VALUES (
        NEWID(), @run_id_fail, @PipelineName, @TableName, @LayerName,
        'FAILED', @start_time_fail, SYSDATETIME(), DATEDIFF(SECOND, @start_time_fail, SYSDATETIME()), 0, ISNULL(@ErrorMessage, 'Unknown Error'), CAST(SYSDATETIME() AS DATE)
    );
END
